#include <iostream>

int main() {
  int number = 42;
  int& ref = number;
  std::cout << "Value: " << ref << std::endl;
  ref = 100;
  std::cout << "Updated number: " << number << std::endl;
  return 0;
}
// Output:
// Value: 42
// Updated number: 100

#include <iostream>

void updateValue(int& ref) {
  ref = 200;
}

int main() {
  int value = 50;
  updateValue(value);
  std::cout << "Updated value: " << value << std::endl;
  return 0;
}
// Output:
// Updated value: 200

#include <iostream>

void updateWithPointer(int* ptr) {
  *ptr = 300;
}

void updateWithReference(int& ref) {
  ref = 400;
}

int main() {
  int value = 100;
  updateWithPointer(&value);
  std::cout << "After pointer: " << value << std::endl;
  updateWithReference(value);
  std::cout << "After reference: " << value << std::endl;
  return 0;
}
// Output:
// After pointer: 300
// After reference: 400

#include <iostream>
#include <string>

void printString(const std::string& text) {
  std::cout << "Text: " << text << std::endl;
}

int main() {
  std::string message = "Hello, C++!";
  printString(message);
  return 0;
}
// Output:
// Text: Hello, C++!

